505→void ALFPTacticsUnit::ApplyDamageToTarget(ALFPTacticsUnit* Target)
506→{
507→    if (!Target || Target->bIsDead) return;
508→
509→    // 基础伤害计算
510→    int32 Damage = AttackPower;
511→
512→    // 伤害随机浮动（10% 范围）
513→    float RandomFactor = FMath::RandRange(0.9f, 1.1f);
514→    Damage = FMath::RoundToInt(Damage * RandomFactor);
515→
516→    // 应用伤害
517→    Target->TakeDamage(Damage);
518→
519→    // 消耗行动力
520→    ConsumeMovePoints(1);
521→}
