523→void ALFPTacticsUnit::HandleDeath()
524→{
525→    bIsDead = true;
526→
527→	// 广播死亡事件
528→    OnDeathDelegate.Broadcast();
529→
530→    // 蓝图事件
531→    OnDeath();
532→
533→    // 通知 GameMode 敌方单位被击杀（掉落追踪）
534→    if (IsEnemy())
535→    {
536→        if (ALFPTurnGameMode* GM = Cast<ALFPTurnGameMode>(GetWorld()->GetAuthGameMode()))
537→        {
538→            GM->OnEnemyUnitKilled(this);
539→        }
540→    }
541→
542→    // 从格子上移除
543→    ALFPHexTile* CurrentTile = GetCurrentTile();
544→    if (CurrentTile)
545→    {
546→        CurrentTile->SetUnitOnTile(nullptr);
547→    }
548→
549→    // 从回合系统中移除
550→    if (ALFPTurnManager* TurnManager = GetTurnManager())
551→    {
552→        TurnManager->UnregisterUnit(this);
553→    }
554→
555→    // 禁用碰撞
556→    SetActorEnableCollision(false);
557→
558→    // 延迟销毁
559→    FTimerHandle TimerHandle;
560→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, [this]()
561→        {
562→            Destroy();
563→        }, 2.0f, false);
564→}
