566→void ALFPTacticsUnit::ChangeAffiliation(EUnitAffiliation NewAffiliation)
567→{
568→	EUnitAffiliation OldAffiliation = Affiliation;
569→	Affiliation = NewAffiliation;
570→
571→    if (NewAffiliation == EUnitAffiliation::UA_Player)
572→    {
573→        if (AIController)
574→        {
575→            AIController->UnPossess();
576→            AIController->Destroy();
577→        }
578→
579→        // 敌人→玩家：记录捕获
580→        if (OldAffiliation == EUnitAffiliation::UA_Enemy)
581→        {
582→            if (ALFPTurnGameMode* GM = Cast<ALFPTurnGameMode>(GetWorld()->GetAuthGameMode()))
583→            {
584→                GM->RecordCapturedUnit(this);
585→            }
586→        }
587→    }
588→
589→    // 阵营变更后重新检查胜负条件（如最后一个敌人背叛）
590→    if (ALFPTurnManager* TurnManager = GetTurnManager())
591→    {
592→        TurnManager->CheckBattleEnd();
593→    }
594→}
