596→ALFPTacticsUnit* ALFPTacticsUnit::FindBestTarget()
597→{
598→    // 获取所有玩家单位
599→    TArray<AActor*> PlayerUnits;
600→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), PlayerUnits);
601→
602→    ALFPTacticsUnit* BestTarget = nullptr;
603→    float BestThreatValue = -MAX_FLT;
604→
605→    for (AActor* Actor : PlayerUnits)
606→    {
607→        ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor);
608→        if (Unit && Unit->IsAlive() && Unit->IsAlly())
609→        {
610→            float ThreatValue = CalculateThreatValue(Unit);
611→            if (ThreatValue > BestThreatValue)
612→            {
613→                BestThreatValue = ThreatValue;
614→                BestTarget = Unit;
615→            }
616→        }
617→    }
618→
619→    return BestTarget;
620→}
