622→ALFPHexTile* ALFPTacticsUnit::FindBestMovementTile(ALFPTacticsUnit* Target)
623→{
624→    ALFPHexGridManager* GridManager = GetGridManager();
625→    if (!GridManager)
626→    {
627→        return nullptr;
628→    }
629→    // 获取所有可移动位置
630→    MovementRangeTiles = GridManager->GetTilesInRange(GetCurrentTile(), GetCurrentMovePoints());
631→
632→    ALFPHexTile* BestTile = nullptr;
633→    float BestPositionValue = -MAX_FLT;
634→
635→    for (ALFPHexTile* Tile : MovementRangeTiles)
636→    {
637→        // 跳过有单位的格子
638→        if (Tile->GetUnitOnTile()) continue;
639→
640→        float PositionValue = CalculatePositionValue(Tile, Target);
641→        if (PositionValue > BestPositionValue)
642→        {
643→            BestPositionValue = PositionValue;
644→            BestTile = Tile;
645→        }
646→    }
647→
648→    return BestTile;
649→}
