651→float ALFPTacticsUnit::CalculateThreatValue(ALFPTacticsUnit* Target)
652→{
653→    // 威胁值 = 目标攻击力
654→    float ThreatValue = Target->GetAttackPower();
655→
656→    // 距离因素（越近威胁越大）
657→    int32 Distance = FLFPHexCoordinates::Distance(
658→        GetCurrentCoordinates(),
659→        Target->GetCurrentCoordinates()
660→    );
661→    float DistanceFactor = 1.0f / FMath::Max(Distance, 1);
662→
663→    //// 应用行为数据
664→    //if (BehaviorData)
665→    //{
