 73→ALFPTacticsUnit* ALFPAIController::FindBestTarget() const
 74→{
 75→    if (!ControlledUnit || !GridManager) return nullptr;
 76→
 77→    // 获取所有玩家单位
 78→    TArray<AActor*> PlayerUnits;
 79→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), PlayerUnits);
 80→
 81→    ALFPTacticsUnit* BestTarget = nullptr;
 82→    float BestThreatValue = -MAX_FLT;
 83→
 84→    for (AActor* Actor : PlayerUnits)
 85→    {
 86→        ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor);
 87→        if (Unit && Unit->IsAlive() && Unit->IsAlly())
 88→        {
 89→            float ThreatValue = CalculateThreatValue(Unit);
 90→            if (ThreatValue > BestThreatValue)
 91→            {
 92→                BestThreatValue = ThreatValue;
 93→                BestTarget = Unit;
 94→            }
 95→        }
 96→    }
 97→
 98→    return BestTarget;
 99→}
