128→ALFPHexTile* ALFPAIController::FindBestMovementTile(ALFPTacticsUnit* Target) const
129→{
130→    if (!ControlledUnit || !Target || !GridManager) return nullptr;
131→
132→    // 获取所有可移动位置
133→    TArray<ALFPHexTile*> MovementRange = GridManager->GetTilesInRange(ControlledUnit->GetCurrentTile(), ControlledUnit->GetCurrentMovePoints());
134→
135→    ALFPHexTile* BestTile = nullptr;
136→    float BestPositionValue = -MAX_FLT;
137→
138→    for (ALFPHexTile* Tile : MovementRange)
139→    {
140→        // 跳过有单位的格子
141→        if (Tile->GetUnitOnTile()) continue;
142→
143→        float PositionValue = CalculatePositionValue(Tile, Target);
144→        if (PositionValue > BestPositionValue)
145→        {
146→            BestPositionValue = PositionValue;
147→            BestTile = Tile;
148→        }
149→    }
150→
151→    return BestTile;
152→}
