154→float ALFPAIController::CalculateThreatValue(ALFPTacticsUnit* Target) const
155→{
156→    if (!ControlledUnit || !Target) return 0.0f;
157→
158→    // 威胁值 = 目标攻击力 * (1 - 目标当前血量/最大血量)
159→    float ThreatValue = Target->GetAttackPower() * (1.0f - (float)Target->GetCurrentHealth() / Target->GetMaxHealth());
160→
161→    // 距离因素（越近威胁越大）
162→    int32 Distance = FLFPHexCoordinates::Distance(
163→        ControlledUnit->GetCurrentCoordinates(),
164→        Target->GetCurrentCoordinates()
165→    );
166→    float DistanceFactor = 1.0f / FMath::Max(Distance, 1);
167→
168→    // 应用行为数据
169→    if (BehaviorData)
170→    {
171→        if (BehaviorData->bPrioritizeWeakTargets)
172→        {
173→            // 增加对低血量目标的权重
174→            float HealthRatio = (float)Target->GetCurrentHealth() / Target->GetMaxHealth();
175→            ThreatValue *= (2.0f - HealthRatio); // 血量越低，威胁值越高
176→        }
177→
178→        // 应用攻击性系数
179→        ThreatValue *= BehaviorData->Aggressiveness;
180→    }
181→
182→    return ThreatValue * DistanceFactor;
183→}
184→
185→float ALFPAIController::CalculatePositionValue(ALFPHexTile* Tile, ALFPTacticsUnit* Target) const
186→{
187→    if (!Tile || !Target) return 0.0f;
188→
189→    float PositionValue = 0.0f;
190→
191→    // 1. 离目标越近越好
192→    int32 DistanceToTarget = FLFPHexCoordinates::Distance(
193→        Tile->GetCoordinates(),
194→        Target->GetCurrentCoordinates()
195→    );
196→    PositionValue += 10.0f / FMath::Max(DistanceToTarget, 1);
197→
198→    // 2. 如果在攻击范围内额外加分
199→    if (DistanceToTarget <= ControlledUnit->GetAttackRange())
200→    {
201→        PositionValue += 20.0f;
202→    }
203→
204→    // 3. 靠近其他敌方单位（团队协作加分）
205→    TArray<AActor*> EnemyUnits;
206→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), EnemyUnits);
207→
208→    for (AActor* Actor : EnemyUnits)
209→    {
210→        ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor);
211→        if (Unit && Unit != ControlledUnit && Unit->IsEnemy() && Unit->IsAlive())
212→        {
213→            int32 DistanceToAlly = FLFPHexCoordinates::Distance(
214→                Tile->GetCoordinates(),
215→                Unit->GetCurrentCoordinates()
216→            );
217→
218→            if (DistanceToAlly <= 2)
219→            {
220→                PositionValue += 5.0f / FMath::Max(DistanceToAlly, 1);
221→            }
222→        }
223→    }
224→
225→    return PositionValue;
226→}
