229→
230→FEnemyActionPlan ALFPAIController::CreateActionPlan(ULFPSkillBase* PreAllocatedSkill)
231→{
232→    FEnemyActionPlan Plan;
233→    Plan.EnemyUnit = ControlledUnit;
234→
235→    if (!ControlledUnit || !GridManager)
236→    {
237→        return Plan;
238→    }
239→
240→    // 1. 选择技能：优先使用预分配的，否则自行选择（会 fallback 到默认攻击）
241→    ULFPSkillBase* ChosenSkill = PreAllocatedSkill ? PreAllocatedSkill : SelectBestSkill();
242→    if (!ChosenSkill)
243→    {
244→        return Plan;
245→    }
246→    Plan.PlannedSkill = ChosenSkill;
247→
248→    // 2. 根据技能的仇恨值选择目标
249→    ALFPTacticsUnit* Target = FindBestSkillTarget(ChosenSkill);
250→    if (!Target)
251→    {
252→        return Plan;
253→    }
254→    Plan.TargetUnit = Target;
255→
256→    // 3. 目标格子 = 目标单位当前所在格子
257→    ALFPHexTile* TargetTile = Target->GetCurrentTile();
258→    if (!TargetTile)
259→    {
260→        return Plan;
261→    }
262→    Plan.TargetTile = TargetTile;
263→
264→    // 4. 寻找最佳施法站位
265→    ALFPHexTile* CasterPos = FindBestCasterPosition(ChosenSkill, TargetTile);
266→    if (!CasterPos)
267→    {
268→        // 找不到合适的施法位置，尝试原地
269→        CasterPos = ControlledUnit->GetCurrentTile();
270→    }
271→    Plan.CasterPositionTile = CasterPos;
272→
273→    // 5. 移动到施法位置
274→    if (CasterPos && CasterPos != ControlledUnit->GetCurrentTile())
275→    {
276→        ControlledUnit->MoveToTile(CasterPos);
277→    }
278→
279→    // 6. 计算技能生效范围（EffectRangeCoords 相对于目标格子偏移）
280→    FLFPHexCoordinates TargetCoords = TargetTile->GetCoordinates();
281→    for (const FLFPHexCoordinates& Offset : ChosenSkill->EffectRangeCoords)
282→    {
283→        FLFPHexCoordinates AbsCoord(
284→            TargetCoords.Q + Offset.Q,
285→            TargetCoords.R + Offset.R
286→        );
287→        if (ALFPHexTile* EffectTile = GridManager->GetTileAtCoordinates(AbsCoord))
288→        {
289→            Plan.EffectAreaTiles.Add(EffectTile);
290→        }
291→    }
292→
293→    // 如果没有定义 EffectRangeCoords，至少包含目标格子本身
294→    if (Plan.EffectAreaTiles.Num() == 0)
295→    {
296→        Plan.EffectAreaTiles.Add(TargetTile);
297→    }
298→
299→    Plan.bIsValid = true;
300→    return Plan;
301→}
