 85→bool ULFPSkillComponent::ExecuteSkill(ULFPSkillBase* Skill, ALFPHexTile* TargetTile)
 86→{
 87→    ALFPTacticsUnit* OwnerUnit = Cast<ALFPTacticsUnit>(GetOwner());
 88→    if (!OwnerUnit || !Skill) return false;
 89→
 90→    if (!OwnerUnit->IsEnemy())
 91→    {
 92→		// 检查技能是否可用
 93→		if (!Skill->CanExecute(TargetTile)) return false;
 94→    }
 95→
 96→    // 执行技能
 97→    Skill->Execute(TargetTile);
 98→
 99→    // 更新技能优先级（降低已使用技能的优先级）
100→    Skill->OnSkillUsed();
101→
102→    // 广播事件
103→    OnSkillExecuted.Broadcast(OwnerUnit, TargetTile);
104→
105→    return true;
106→}
