134→float ULFPSkillBase::CalculateHatredValue_Implementation(ALFPTacticsUnit* Caster, ALFPTacticsUnit* Target) const
135→{
136→    if (!Caster || !Target) return 0.0f;
137→
138→    // 基础仇恨 = 目标攻击力（威胁越大越优先打）
139→    float Hatred = (float)Target->GetAttackPower();
140→
141→    // 距离系数（越近仇恨越高）
142→    int32 Dist = FLFPHexCoordinates::Distance(
143→        Caster->GetCurrentCoordinates(),
144→        Target->GetCurrentCoordinates()
145→    );
146→    float DistanceFactor = 1.0f / FMath::Max(Dist, 1);
147→
148→    return Hatred * DistanceFactor;
149→}
